import './Home.css';
import { useState } from 'react';

function Home() {

	const [gameName, setGameName] = useState('');

	return (
		<>
		<div className="title">
			RED-TETRIS
		</div>
		<div className="create-game">
			<input className="game-name" maxLength="10" placeholder="Entrer a name for create the game room" value={gameName} onChange={(e) => setGameName(e.target.value)} />
			<button className='create-game-btn' onClick={() => {console.log()}}> Creer </button>
		</div>
		</>
	);
}

export default Home;
